"use client";

import { useQuery } from "@tanstack/react-query";
import { getDashboardMetrics } from "@/lib/adminApi";
import {
  FileText,
  CheckCircle2,
  XCircle,
  Users,
  Tags,
  TrendingUp,
} from "lucide-react";

const cards = [
  {
    key: "casosTotales" as const,
    title: "Casos Totales",
    icon: FileText,
    gradient: "from-blue-500 to-cyan-500",
    iconBg: "from-blue-500/20 to-cyan-500/20",
  },
  {
    key: "casosAbiertos" as const,
    title: "Casos Abiertos",
    icon: CheckCircle2,
    gradient: "from-blue-600 to-sky-500",
    iconBg: "from-blue-600/20 to-sky-500/20",
  },
  {
    key: "casosCerrados" as const,
    title: "Casos Cerrados",
    icon: XCircle,
    gradient: "from-indigo-500 to-blue-500",
    iconBg: "from-indigo-500/20 to-blue-500/20",
  },
  {
    key: "usuariosTotales" as const,
    title: "Usuarios Activos",
    icon: Users,
    gradient: "from-sky-500 to-blue-500",
    iconBg: "from-sky-500/20 to-blue-500/20",
  },
  {
    key: "categoriasTotales" as const,
    title: "Categorías",
    icon: Tags,
    gradient: "from-blue-700 to-indigo-600",
    iconBg: "from-blue-700/20 to-indigo-600/20",
  },
] as const;

function LoadingSkeleton() {
  return (
    <div className="mt-8 grid grid-cols-1 gap-4 sm:grid-cols-2 xl:grid-cols-3">
      {[...Array(5)].map((_, i) => (
        <div key={i} className="animate-pulse rounded-2xl bg-slate-100 p-6 h-32" />
      ))}
    </div>
  );
}

export default function HomePage() {
  const metricsQuery = useQuery({
    queryKey: ["dashboard", "metrics"],
    queryFn: getDashboardMetrics,
  });

  const metrics = metricsQuery.data || {
    casosTotales: 0,
    casosAbiertos: 0,
    casosCerrados: 0,
    usuariosTotales: 0,
    categoriasTotales: 0,
  };

  return (
    <section className="space-y-8">
      {/* Header */}
      <div className="space-y-2">
        <div className="flex items-center gap-3">
          <div className="flex h-10 w-10 items-center justify-center rounded-lg bg-gradient-to-br from-blue-500 to-cyan-500 shadow-lg">
            <TrendingUp size={20} className="text-white" />
          </div>
          <h1 className="text-4xl font-black bg-gradient-to-r from-slate-900 to-slate-700 bg-clip-text text-transparent">
            Dashboard
          </h1>
        </div>
        <p className="text-slate-600 font-medium">Métricas globales en tiempo real</p>
      </div>

      {/* Error State */}
      {metricsQuery.isError && (
        <div className="rounded-2xl border border-blue-200 bg-gradient-to-r from-blue-50 to-sky-50 p-6 shadow-sm">
          <p className="text-sm font-semibold text-blue-700">
            No fue posible cargar las métricas. Intenta más tarde.
          </p>
        </div>
      )}

      {/* Loading State */}
      {metricsQuery.isLoading && <LoadingSkeleton />}

      {/* Metrics Grid */}
      {!metricsQuery.isLoading && !metricsQuery.isError && (
        <div className="grid grid-cols-1 gap-6 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-5">
          {cards.map((card) => {
            const Icon = card.icon;
            const value = metrics[card.key];

            return (
              <article
                key={card.key}
                className="group relative overflow-hidden rounded-2xl bg-white p-6 shadow-lg transition-all duration-300 hover:shadow-xl hover:shadow-slate-300/20"
              >
                {/* Background Gradient */}
                <div
                  className={`absolute inset-0 bg-gradient-to-br ${card.iconBg} opacity-0 transition-opacity duration-300 group-hover:opacity-100`}
                />

                {/* Content */}
                <div className="relative space-y-4">
                  {/* Icon */}
                  <div
                    className={`inline-flex h-12 w-12 items-center justify-center rounded-xl bg-gradient-to-br ${card.gradient} shadow-lg shadow-slate-400/20`}
                  >
                    <Icon size={24} className="text-white" />
                  </div>

                  {/* Text */}
                  <div className="space-y-2">
                    <p className="text-sm font-semibold text-slate-600 group-hover:text-slate-700 transition-colors">
                      {card.title}
                    </p>
                    <p
                      className={`text-3xl font-black bg-gradient-to-br ${card.gradient} bg-clip-text text-transparent`}
                    >
                      {value.toLocaleString()}
                    </p>
                  </div>
                </div>

                {/* Border Gradient (hover effect) */}
                <div
                  className={`absolute inset-0 rounded-2xl border-2 from-blue-500 to-cyan-500 bg-gradient-to-br opacity-0 transition-opacity duration-300 group-hover:opacity-10 pointer-events-none`}
                />
              </article>
            );
          })}
        </div>
      )}
    </section>
  );
}
